/**
 * Find engrams similar to a given engram by its existing vector.
 */
export const retrievalSimilar = <ThrowOnError extends boolean = false>(
  options?: Options<RetrievalSimilarData, ThrowOnError>
): RequestResult<RetrievalSimilarResponses, RetrievalSimilarErrors, ThrowOnError> =>
  (options?.client ?? client).post<RetrievalSimilarResponses, RetrievalSimilarErrors, ThrowOnError>(
    {
      url: '/retrieval/similar',
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options?.headers,
      },
    }
  );

/**
 * Retrieval layer health and coverage counts.
 */
export const retrievalStats = <ThrowOnError extends boolean = false>(
  options?: Options<RetrievalStatsData, ThrowOnError>
): RequestResult<RetrievalStatsResponses, unknown, ThrowOnError> =>
  (options?.client ?? client).get<RetrievalStatsResponses, unknown, ThrowOnError>({
    url: '/retrieval/stats',
    ...options,
  });

